#define fp float

#define NUMBER_PAR_PER_BOX 100

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;

	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__kernel void
kernel_gpu_opencl(	par_str par,
					dim_str dim,
					__global box_str* box,
					__global FOUR_VECTOR* rv,
					__global fp* qv,
					__global FOUR_VECTOR* fv)
{
	int l = get_group_id(0);
	int i = get_local_id(0);

	if ((long)l >= dim.number_boxes || i >= NUMBER_PAR_PER_BOX) {
		return;
	}

	fp alpha = par.alpha;
	fp a2 = (fp)2.0f * alpha * alpha;

	long first_i = box[l].offset;
	__global FOUR_VECTOR* rA = &rv[first_i];
	__global FOUR_VECTOR* fA = &fv[first_i];

	FOUR_VECTOR rAi = rA[i];
	FOUR_VECTOR ftmp = fA[i];

	for (int k = 0; k < (1 + box[l].nn); k++) {

		int pointer;
		if (k == 0) {
			pointer = l;
		}
		else {
			pointer = box[l].nei[k-1].number;
		}

		long first_j = box[pointer].offset;
		__global FOUR_VECTOR* rB = &rv[first_j];
		__global fp* qB = &qv[first_j];

		for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {

			fp r2 = rAi.v + rB[j].v - (rAi.x * rB[j].x + rAi.y * rB[j].y + rAi.z * rB[j].z);
			fp u2 = a2 * r2;
			fp vij = exp(-u2);
			fp fs = (fp)2.0f * vij;

			fp dx = rAi.x - rB[j].x;
			fp dy = rAi.y - rB[j].y;
			fp dz = rAi.z - rB[j].z;

			fp fxij = fs * dx;
			fp fyij = fs * dy;
			fp fzij = fs * dz;

			fp q = qB[j];
			ftmp.v += q * vij;
			ftmp.x += q * fxij;
			ftmp.y += q * fyij;
			ftmp.z += q * fzij;
		}
	}

	fA[i] = ftmp;
}
